<?php
namespace App\Modules\Hr\Recruitment\Actions; use App\Modules\Hr\Core\Services\HrAuditService;use App\Modules\Hr\Core\Services\TenantContext;use App\Modules\Hr\Recruitment\Models\HrApplication;use App\Modules\Hr\Recruitment\Models\HrApplicationStage;use App\Modules\Hr\Recruitment\Models\HrCandidate;use App\Modules\Hr\Recruitment\Models\HrJobPosting;use Illuminate\Support\Facades\DB;
class CreateApplicationAction{public function __construct(private HrAuditService $audit){}public function execute(HrJobPosting $posting,array $candidateData):HrApplication{$tenant=app(TenantContext::class)->getId();abort_unless(auth()->user()?->hasHrPermission('hr.recruitment.manage_candidates'),403);abort_unless($posting->legal_entity_id===$tenant&&in_array($posting->status,['draft','published'],true),404);abort_if(blank($candidateData['first_name']??null)||blank($candidateData['last_name']??null)||!filter_var($candidateData['email']??'',FILTER_VALIDATE_EMAIL)||blank($candidateData['consent_note']??null),422,'Aday bilgileri ve açık rıza kaydı zorunludur.');return DB::transaction(function()use($posting,$candidateData,$tenant){$candidate=HrCandidate::firstOrCreate(['legal_entity_id'=>$tenant,'email'=>mb_strtolower(trim($candidateData['email']))],['first_name'=>trim($candidateData['first_name']),'last_name'=>trim($candidateData['last_name']),'phone'=>$candidateData['phone']??null,'source'=>$candidateData['source']??null,'consent_note'=>$candidateData['consent_note'],'consented_at'=>now(),'created_by'=>auth()->id()]);$application=HrApplication::firstOrCreate(['job_posting_id'=>$posting->id,'candidate_id'=>$candidate->id],['legal_entity_id'=>$tenant,'current_stage'=>'applied','status'=>'active']);if($application->wasRecentlyCreated)HrApplicationStage::create(['legal_entity_id'=>$tenant,'application_id'=>$application->id,'stage'=>'applied','sequence'=>1,'status'=>'completed','completed_at'=>now(),'acted_by'=>auth()->id()]);$this->audit->log('recruitment_application_created',$application);return $application;});}}
